using UnityEngine;
using System.Linq;
using System.Collections.Generic;

public class LINQExample : MonoBehaviour
{
    // Sample data
    private List<Enemy> enemies;
    private List<Item> inventory;

    void Start()
    {
        // Initialize data
        enemies = new List<Enemy>
        {
            new Enemy { Name = "Goblin", Health = 30, Attack = 8, Experience = 20, IsBoss = false },
            new Enemy { Name = "Orc", Health = 50, Attack = 12, Experience = 35, IsBoss = false },
            new Enemy { Name = "Skeleton", Health = 25, Attack = 6, Experience = 15, IsBoss = false },
            new Enemy { Name = "Dragon", Health = 200, Attack = 25, Experience = 150, IsBoss = true },
            new Enemy { Name = "Troll", Health = 80, Attack = 18, Experience = 60, IsBoss = false },
            new Enemy { Name = "Boss", Health = 150, Attack = 30, Experience = 100, IsBoss = true }
        };

        inventory = new List<Item>
        {
            new Item { Name = "Sword", Value = 50, Type = ItemType.Weapon },
            new Item { Name = "Shield", Value = 40, Type = ItemType.Armor },
            new Item { Name = "Potion", Value = 25, Type = ItemType.Consumable },
            new Item { Name = "Key", Value = 10, Type = ItemType.Key },
            new Item { Name = "Bow", Value = 35, Type = ItemType.Weapon },
            new Item { Name = "Helmet", Value = 30, Type = ItemType.Armor }
        };

        RunLINQExamples();
    }

    void RunLINQExamples()
    {
        // 1. Where — filter
        var strongEnemies = enemies.Where(e => e.Health > 40);
        Debug.Log("=== Strong Enemies (Health > 40) ===");
        foreach (var e in strongEnemies)
        {
            Debug.Log(e.Name + " (HP: " + e.Health + ")");
        }

        // 2. Select — transform
        var enemyNames = enemies.Select(e => e.Name);
        Debug.Log("=== Enemy Names ===");
        foreach (string name in enemyNames)
        {
            Debug.Log(name);
        }

        // 3. OrderBy — sort
        var sortedEnemies = enemies.OrderBy(e => e.Health);
        Debug.Log("=== Enemies Sorted by Health ===");
        foreach (var e in sortedEnemies)
        {
            Debug.Log(e.Name + " (HP: " + e.Health + ")");
        }

        // 4. OrderByDescending — sort descending
        var sortedDescending = enemies.OrderByDescending(e => e.Experience);
        Debug.Log("=== Enemies Sorted by XP (Descending) ===");
        foreach (var e in sortedDescending)
        {
            Debug.Log(e.Name + " (XP: " + e.Experience + ")");
        }

        // 5. First / FirstOrDefault
        var firstBoss = enemies.FirstOrDefault(e => e.IsBoss);
        if (firstBoss != null)
        {
            Debug.Log("First Boss: " + firstBoss.Name);
        }

        // 6. Sum / Average / Min / Max
        int totalHealth = enemies.Sum(e => e.Health);
        float avgAttack = enemies.Average(e => e.Attack);
        int minHealth = enemies.Min(e => e.Health);
        int maxHealth = enemies.Max(e => e.Health);

        Debug.Log("Total Health: " + totalHealth);
        Debug.Log("Average Attack: " + avgAttack);
        Debug.Log("Min Health: " + minHealth);
        Debug.Log("Max Health: " + maxHealth);

        // 7. Count
        int bossCount = enemies.Count(e => e.IsBoss);
        Debug.Log("Number of Bosses: " + bossCount);

        // 8. Any / All
        bool hasBoss = enemies.Any(e => e.IsBoss);
        bool allStrong = enemies.All(e => e.Health > 20);
        Debug.Log("Has Boss: " + hasBoss);
        Debug.Log("All Strong: " + allStrong);

        // 9. GroupBy
        var groupedByType = inventory.GroupBy(i => i.Type);
        Debug.Log("=== Inventory Grouped by Type ===");
        foreach (var group in groupedByType)
        {
            Debug.Log(group.Key + ": " + group.Count() + " items");
            foreach (var item in group)
            {
                Debug.Log("  - " + item.Name);
            }
        }

        // 10. SelectMany
        var allItems = inventory.Select(i => i.Name);
        Debug.Log("=== All Items ===");
        foreach (string name in allItems)
        {
            Debug.Log(name);
        }
    }
}

// Data classes
public class Enemy
{
    public string Name { get; set; }
    public int Health { get; set; }
    public int Attack { get; set; }
    public int Experience { get; set; }
    public bool IsBoss { get; set; }
}

public enum ItemType
{
    Weapon,
    Armor,
    Consumable,
    Key
}

public class Item
{
    public string Name { get; set; }
    public int Value { get; set; }
    public ItemType Type { get; set; }
}

